CREATE TABLE timetable.building
(
  id           SERIAL PRIMARY KEY,
  org_id       INT                      NOT NULL,
  name         VARCHAR(255)             NOT NULL,
  is_default   BOOLEAN                  NOT NULL DEFAULT FALSE,
  deleted      BOOLEAN                  NOT NULL DEFAULT FALSE,
  created_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP
);

ALTER TABLE timetable.room
  ADD COLUMN building_id INT;

ALTER TABLE timetable.room
  ADD CONSTRAINT fk_room_building
    FOREIGN KEY (building_id) REFERENCES timetable.building (id);
ALTER TABLE timetable.room DROP COLUMN type;
